import requests
from google_adk.tools import tool

@tool
def fetch_user_dashboard(uid: str) -> dict:
    """
    Fetches the user dashboard info.
    """
    try:
        r = requests.get(f"https://api.internal/dash/{uid}", timeout=5)
        r.raise_for_status()
        return {"status": "success", "data": r.json()}
    except requests.exceptions.HTTPError as he:
        return {"status": "failed", "error": f"HTTP Error: {he.response.status_code}"}
    except Exception as e:
        return {"status": "error", "error": str(e)}
